22232	/* Load token strings, special token ids, and merge ranks from GGUF metadata. */
22233	static void vocab_load(ds4_vocab *vocab, const ds4_model *model) {
22234	    memset(vocab, 0, sizeof(*vocab));
22235	
22236	    ds4_array_ref tokens;
22237	    ds4_array_ref merges;
22238	    if (!model_get_array(model, "tokenizer.ggml.tokens", &tokens) ||
22239	        tokens.type != GGUF_VALUE_STRING ||
22240	        tokens.len > INT32_MAX) {
22241	        ds4_die("GGUF tokenizer token table is missing or invalid");
22242	    }
22243	    if (!model_get_array(model, "tokenizer.ggml.merges", &merges) ||
22244	        merges.type != GGUF_VALUE_STRING) {
22245	        ds4_die("GGUF tokenizer merge table is missing or invalid");
22246	    }
22247	
22248	    vocab->n_vocab = (int)tokens.len;
22249	    vocab->token = xcalloc((size_t)vocab->n_vocab, sizeof(vocab->token[0]));
22250	    table_init(&vocab->token_to_id, tokens.len);
22251	
22252	    ds4_cursor c = cursor_at(model, tokens.data_pos);
22253	    for (int i = 0; i < vocab->n_vocab; i++) {
22254	        if (!cursor_string(&c, &vocab->token[i])) ds4_die(c.error);
22255	        table_put(&vocab->token_to_id, vocab->token[i], i);
22256	    }
22257	
22258	    table_init(&vocab->merge_rank, merges.len);
22259	    c = cursor_at(model, merges.data_pos);
22260	    for (uint64_t i = 0; i < merges.len; i++) {
22261	        ds4_str merge;
22262	        if (!cursor_string(&c, &merge)) ds4_die(c.error);
22263	        table_put(&vocab->merge_rank, merge, (int)i);
22264	    }
22265	
22266	    vocab->bos_id       = vocab_lookup(vocab, "<｜begin▁of▁sentence｜>");
22267	    vocab->eos_id       = vocab_lookup(vocab, "<｜end▁of▁sentence｜>");
22268	    vocab->user_id      = vocab_lookup(vocab, "<｜User｜>");
22269	    vocab->assistant_id = vocab_lookup(vocab, "<｜Assistant｜>");
22270	    vocab->think_start_id = vocab_lookup(vocab, "<think>");
22271	    vocab->think_end_id = vocab_lookup(vocab, "</think>");
22272	    vocab->dsml_id = vocab_lookup(vocab, "｜DSML｜");
22273	}
