22275	static void vocab_free(ds4_vocab *vocab) {
22276	    free(vocab->token);
22277	    table_free(&vocab->token_to_id);
22278	    table_free(&vocab->merge_rank);
22279	    memset(vocab, 0, sizeof(*vocab));
22280	}
