22282	/* Build the DS4 chat prompt: BOS, optional system text, user prompt, assistant
22283	 * marker, and either <think> or </think> depending on the requested mode.  Max
22284	 * thinking is only a prompt prefix: the model still enters through <think>. */
22285	static void encode_chat_prompt(
22286	        const ds4_vocab *vocab,
22287	        const char      *system,
22288	        const char      *prompt,
22289	        ds4_think_mode   think_mode,
22290	        token_vec       *out) {
22291	    token_vec_push(out, vocab->bos_id);
22292	    if (think_mode == DS4_THINK_MAX) {
22293	        bpe_tokenize_text(vocab, DS4_REASONING_EFFORT_MAX_PREFIX, out);
22294	    }
22295	    if (system && system[0]) {
22296	        bpe_tokenize_text(vocab, system, out);
22297	    }
22298	    token_vec_push(out, vocab->user_id);
22299	    bpe_tokenize_text(vocab, prompt, out);
22300	    token_vec_push(out, vocab->assistant_id);
22301	    if (ds4_think_mode_enabled(think_mode)) {
22302	        token_vec_push(out, vocab->think_start_id);
22303	    } else {
22304	        token_vec_push(out, vocab->think_end_id);
22305	    }
22306	}
