22313	    struct special {
22314	        const char *text;
22315	        int token;
22316	    } specials[] = {
22317	        {"<｜begin▁of▁sentence｜>", vocab->bos_id},
22318	        {"<｜end▁of▁sentence｜>",   vocab->eos_id},
22319	        {"<｜User｜>",              vocab->user_id},
22320	        {"<｜Assistant｜>",         vocab->assistant_id},
22321	        {"<think>",                vocab->think_start_id},
22322	        {"</think>",               vocab->think_end_id},
22323	        {"｜DSML｜",                vocab->dsml_id},
22324	    };
22325	
22326	    for (size_t i = 0; i < sizeof(specials) / sizeof(specials[0]); i++) {
22327	        size_t n = strlen(specials[i].text);
22328	        if (!strncmp(p, specials[i].text, n)) {
22329	            *token = specials[i].token;
